152	// Decomposition holds the rationale and sub-plan summaries when
153	// the agent's runtime estimate exceeds the implement-stage budget.
154	// Stored in the audit log but not acted upon until D3/D4.
155	type Decomposition struct {
156		Rationale string           `json:"rationale"`
157		SubPlans  []SubPlanSummary `json:"sub_plans"`
158	}
159	
160	// Waves derives the topological dispatch order for a decomposition's
161	// sub_plans from their depends_on edges (#1258), returning ordered waves of
162	// 0-based sub-plan indices. Wave 0 holds every slice with no unsatisfied
163	// dependency; each subsequent wave holds the slices whose dependencies all
164	// appeared in an earlier wave. Within a wave, indices are emitted in
165	// ascending order for deterministic output. A decomposition with no
166	// depends_on anywhere collapses to a single wave [[0,1,...,n-1]]
167	// (back-compat). It is a pure Kahn topological sort with no side effects;
168	// no downstream dispatch consumes the result yet (slice B, #1278).
169	//
170	// Waves fails loud rather than silently dropping a slice:
171	//   - a depends_on index outside [0, len(sub_plans)) (out-of-range or negative);
172	//   - a slice depending on itself (self-dependency);
173	//   - a dependency cycle that leaves some slices unplaceable.
174	//
175	// A nil decomposition or one with no sub_plans returns (nil, nil).
176	func Waves(d *Decomposition) ([][]int, error) {
177		if d == nil || len(d.SubPlans) == 0 {
178			return nil, nil
179		}
180		n := len(d.SubPlans)
181	
182		// Validate every edge before layering so a malformed index is reported
183		// as such rather than masquerading as a cycle.
184		for i, sp := range d.SubPlans {
185			for _, dep := range sp.DependsOn {
186				if dep < 0 || dep >= n {
187					return nil, fmt.Errorf("sub_plan %d depends_on index %d out of range [0,%d)", i, dep, n)
188				}
189				if dep == i {
190					return nil, fmt.Errorf("sub_plan %d depends_on itself (index %d)", i, dep)
191				}
192			}
193		}
194	
195		// Kahn layering: a node joins a wave once every node it depends on has
196		// been placed in an earlier wave. Iterating i ascending keeps each wave
197		// (and the cycle report below) in ascending index order.
198		placed := make([]bool, n)
199		remaining := n
200		var waves [][]int
201		for remaining > 0 {
202			var wave []int
203			for i := 0; i < n; i++ {
204				if placed[i] {
205					continue
206				}
207				ready := true
208				for _, dep := range d.SubPlans[i].DependsOn {
209					if !placed[dep] {
210						ready = false
211						break
212					}
213				}
214				if ready {
215					wave = append(wave, i)
216				}
217			}
218			if len(wave) == 0 {
219				// No node became ready this pass: every unplaced node sits on a
220				// dependency cycle.
221				var stuck []int
222				for i := 0; i < n; i++ {
