121			argvMu   sync.Mutex
122		)
123		withFakeSpawn(t, func(_ context.Context, _ string, argv, _ []string, _ *mcp.CallToolRequest, _ any) ([]RunnerEvent, []string, int, error) {
124			cur := atomic.AddInt32(&inFlight, 1)
125			for {
126				p := atomic.LoadInt32(&peak)
127				if cur <= p || atomic.CompareAndSwapInt32(&peak, p, cur) {
128					break
129				}
130			}
131			time.Sleep(25 * time.Millisecond) // hold the slot so concurrency can build
132			atomic.AddInt32(&inFlight, -1)
