300			t.Fatalf("createdRefs = %v, want exactly 1 consolidated branch create", createdRefs)
301		}
302		if !strings.HasPrefix(createdRefs[0], "fishhawk/run-") {
303			t.Errorf("created ref = %q, want a fishhawk/run- consolidated branch", createdRefs[0])
304		}
305		// Both slices merged in ascending slice order.
306		if len(mergeHeads) != 2 {
307			t.Fatalf("mergeHeads = %v, want 2 merges", mergeHeads)
308		}
309		if !strings.HasSuffix(mergeHeads[0], "/slice-0") || !strings.HasSuffix(mergeHeads[1], "/slice-1") {
310			t.Errorf("merge order = %v, want slice-0 then slice-1 (ascending)", mergeHeads)
311		}
