321		// The children_settled payload is byte-identical to the sweeper's so the
322		// children_status classifier reports correctly — assert its structured
323		// shape, not just that an entry exists: child_run_ids = the actual child
324		// run ids, parent_stage_id = the implement stage, resolved_to_state =
325		// succeeded.
326		settled := consolidateAuditPayload(t, f.au, f.parent.ID, "children_settled")
