328			t.Errorf("children_settled parent_stage_id = %v, want %q", got, want)
329		}
330		if got := settled["resolved_to_state"]; got != string(run.StageStateSucceeded) {
331			t.Errorf("children_settled resolved_to_state = %v, want succeeded", got)
332		}
333		gotChildIDs := stringSetFromAny(t, settled["child_run_ids"])
334		wantChildIDs := map[string]bool{}
335		kids, _ := f.rr.ListRuns(context.Background(), run.ListRunsFilter{DecomposedFrom: &f.parent.ID})
336		for _, k := range kids {
337			wantChildIDs[k.ID.String()] = true
338		}
