375	// slice that fails to merge fails the parent implement stage category-B, emits
376	// a slice_integration_conflict audit carrying the conflicting slice index +
377	// child run id, and returns a 200 slice_conflict body (the E24.2 contract).
378	func TestConsolidateRun_SliceConflict(t *testing.T) {
