577	// TestConsolidateRun_InFlightChildBeyondFirstPage is the >100-child pagination
578	// boundary (high/correctness). A fan-out exceeding one page must not be
579	// inspected partially: a single Limit-capped ListRuns would see only the first
580	// page and miss a later in-flight child, then wrongly transition the parent and
581	// Advance early. Here slice 100 (on page 2) is still running while every other
582	// child has succeeded; the handler must page past the first 100 and return 409
583	// children_in_flight naming that child — NOT proceed to integration.
584	func TestConsolidateRun_InFlightChildBeyondFirstPage(t *testing.T) {
585		gh := newConsolidateGitHub()
586		const total = 101 // 0..100 — slice 100 lands on the second page
587		children := make([]childSpec, total)
588		for i := 0; i < total; i++ {
589			st := run.StateSucceeded
590			if i == total-1 {
591				st = run.StateRunning // the lone in-flight child, on page 2
592			}
593			children[i] = childSpec{sliceIndex: i, state: st}
594		}
595		f := seedConsolidateFixture(t, gh, true, children)
596		f.s.cfg.RunRepo = &pagingRunRepo{f.rr} // honor Limit/Offset so paging is exercised
597	
598		w := postConsolidate(t, f.s, f.parent.ID, withAuth)
599		if w.Code != http.StatusConflict {
600			t.Fatalf("status = %d, want 409 (in-flight child beyond first page must be seen):\n%s", w.Code, w.Body.String())
601		}
602		if code := decodeError(t, w); code != "children_in_flight" {
603			t.Errorf("error = %q, want children_in_flight", code)
604		}
605		// Premature integration must NOT have run.
606		if gh.mergeCount() != 0 {
607			t.Errorf("merges = %d, want 0 (no fan-in while a page-2 child is in flight)", gh.mergeCount())
608		}
609		if f.impl.State != run.StageStateAwaitingChildren {
610			t.Errorf("parent implement state = %q, want awaiting_children (unchanged)", f.impl.State)
611		}
612	}
