		t.Fatalf("status = %d, want 400:\n%s", w.Code, w.Body.String())
	}
	if code := decodeError(t, w); code != "not_a_decomposed_parent" {
		t.Errorf("error = %q, want not_a_decomposed_parent", code)
	}
}

