	reviseBody       reviseRequest
	reviseResp       map[uuid.UUID]Stage
	reviseStatus     int
	reviseErrBody    string
	reviseCalledByID map[uuid.UUID]int

	// #984 fixtures: POST /v0/concerns/{id}/waive.
