	// waiveCalledByID counts waive calls per concern id.
	waiveBody       waiveConcernRequest
	waiveResp       map[uuid.UUID]WaivedConcern
	waiveStatus     int
	waiveErrBody    string
	waiveCalledByID map[uuid.UUID]int

