			Timestamp: time.Date(2026, 5, 15, 10, 0, 0, 0, time.UTC),
		},
		Summary: "Add a dryRun flag to the dispatcher.",
		Scope: PlanScope{
			Files: []PlanScopeFile{
				{Path: "backend/internal/webhook/dispatcher.go", Operation: "modify"},
			},
			EstimatedLinesChanged: 40,
		},
		Approach: []PlanApproachStep{
